messages.content:
{
  "intent": "check_and_fix",
  "intent_description": "Host 192.168.0.12 cannot reach 172.16.0.12 (25 pings sent, 0 successful). Restore IP reachability so pings succeed between the two subnets.",
  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "No IP-level reachability from 192.168.0.12 to 172.16.0.12 — routers lack routes between 192.168.0.0/24 and 172.16.0.0/24 (diagnostic outputs missing).",
    "fix_summary": "Add reciprocal static routes on the edge routers so each router has a route to the other's LAN (172.16.0.0/24 and 192.168.0.0/24).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router1",
        "action": "add_static_route",
        "target": "172.16.0.0/24",
        "parameters": [
          "172.16.0.0/24",
          "172.16.0.1"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "192.168.0.0/24",
          "192.168.0.1"
        ]
      }
    ]
  }
}

